INSERT INTO `faq` (`id`, `question`, `answer`, `created_at`) VALUES
(6, 'Q: I heard PTE scoring changed in 2025/2026. Is it harder now?', 'A: Not necessarily \"harder,\" but it is smarter. Pearson introduced two new tasksâ€”Summarize Group Discussion and Respond to a Situationâ€”and added human oversight to specific sections to penalize \"robotic\" templates.\r\nAyanâ€™s Academy Tip: Our Authentic Practice Portal is 100% updated with these new 2026 task types, so you wonâ€™t be surprised on exam day.', '2026-03-27 10:46:48'),
(7, 'Q: How long does it take to get my results?', 'A: PTE remains the fastest. Most students receive their scores within 2 business days, often even within 24 hours.', '2026-03-27 10:47:52'),
(8, 'Q: Can I use PTE Academic for Canada PR?', 'A: No. For Canadian Permanent Residency (Express Entry, etc.), you must take PTE Core. PTE Academic is strictly for study permits and professional registration.', '2026-03-27 10:48:28'),
(9, 'Q: Does PTE Core have an essay?', 'A: No. Instead of a long academic essay, you have a \"Write Email\" task (80â€“120 words), which is much more practical and easier to master with the right structure.', '2026-03-27 10:49:07'),
(10, 'Q: Is the TOEFL still 3 hours long?', 'A: No! As of January 21, 2026, the TOEFL iBT has been shortened to roughly 90 minutes. It is now a streamlined, \"high-intensity\" test.', '2026-03-27 10:50:52'),
(11, 'Q: What is \"Adaptive Testing\" in the new TOEFL?', 'A: The Reading and Listening sections are now multistage adaptive. If you do well in the first set of questions, the second set becomes more challenging (and carries more weight for a high score).\r\nAyanâ€™s Academy Tip: Our trainers teach you how to \"unlock\" the high-scoring second module by mastering the first stage\'s precision.', '2026-03-27 10:51:43'),
(12, 'Q: Can I still use a pencil for the paper-based test?', 'A: Important Update: In most regions for 2026, pencils are retired. You must use a black ballpoint pen for Listening, Reading, and Writing to ensure the new AI-scanning technology can read your answers clearly.', '2026-03-27 10:52:22'),
(13, 'Q: What is the \"One Skill Retake\" (OSR)?', 'A: If you miss your target score in just one section (e.g., you got a 6.5 in Writing but need a 7.0), you can retake only that section within 60 days. This is currently available for Computer-Delivered IELTS only.', '2026-03-27 10:52:46'),
(14, 'Q: Are templates still effective for IELTS Writing?', 'A: Examiners in 2026 are strictly trained to penalize \"memorized templates.\" They are looking for original thought and specific answers to the prompt. At Ayan\'s Academy, we teach you Critical Thinking Frameworks rather than just \"filling in the blanks.\"', '2026-03-27 10:53:16'),
(15, 'Why Ayanâ€™s Academy?', '*Worldwide Recognized Trainers: Our experts are certified to teach across all four exam types.\r\n*Authentic Practice Portal: We provide the only portal that mirrors the 2026 UI changes (like the new progress bars and audio waveforms).\r\n*AI + Human Feedback: We use the same hybrid scoring approach that major tests have adopted this year.', '2026-03-27 10:54:14');

