(2, 'uploads/ielts-courses/1775976977_8798.jpg', 'IELTS 1 to 1 Long Course (Online)', 'Check', '44', 30000.00, 'Advanced', 22, '2', '<p>Check</p>', '<p>Check</p>', '2026-04-11 07:25:18'),
(3, 'uploads/ielts-courses/1775976959_3565.jpg', 'IELTS 1 to 1 Long Course (Online)', 'Check', '40', 20000.00, 'Advanced', 15, '2', '<p>Check</p>', '<p>Check</p>', '2026-04-11 07:26:40'),
(4, 'uploads/ielts-courses/1775976938_8236.jpg', 'IELTS 1 to 1 Long Course (Online)', 'Check', '44', 30000.00, 'Advanced', 22, '2', '<p>Check</p>', '<p>Check</p>', '2026-04-11 07:29:08');
