  `id` int(11) NOT NULL,
  `type` enum('mission','vision') NOT NULL,
  `description` longtext NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `mission_vision`
--

INSERT INTO `mission_vision` (`id`, `type`, `description`, `created_at`) VALUES
(2, 'mission', '<ul><li>&nbsp;To guide students to fulfill their dream of studying abroad and help to reach their destination whatever they aim to do.</li><li>&nbsp;To instruct with proper curriculum for fulfilling their requirement.</li><li>&nbsp;To ensure competency focusing on solving their drawbacks and enhance their ability to achieve the required skill.</li><li>Get you into top academic institutions where you can meet your thrust for knowledge.</li><li>To disclose everything frankly without keeping no hidden fees.</li><li>Find out the quality of a student so that we are able to show him the best option for an excellent career.</li><li>Benefit from the experience of huge amount students before you.</li><li>Providing data points from real students and admissions results.</li><li>We study what acts and doesn’t, then apply it to your application to make it successful.</li><li>To work with diligence, honesty, courage, far play, and initiative-taking along with the union of our experts and our ability to respond effectively to the positive and productive changes taking place in all aspects of life.</li><li>We care properly and equally to all students of any kind of background and try to create a harmonious environment for learning and support.</li></ul>', '2026-03-23 10:41:28'),
(3, 'vision', '<p>To become the leading educational consultant in Bangladesh for students aspiring for Bachelors/ Masters/ PhD/ Post Doctorate programs in USA/UK/Canada and Australia.</p><p>To be the pioneer in providing one-stop study abroad solutions for the students and help them achieve their goals through proper counseling &amp; guidance, to&nbsp;add value for our&nbsp;partner institutions and all other stakeholders.</p><p>To provide the English Language Test classes and other language courses required in order to get enrolled in the institutions so that our students become appreciated with higher acceptance.</p><p>We target at transforming the lives of the students by serving the right education and career outline for students. Backed by our team of expert consultants, we hope to offer students an opportunity to select the right universities thereby facilitating lifelong learning. We ensure that each of our students goes through a hassle-free admission process to the University of their choice. We aim at informing our valuable students about the best educational institutions thus improving the level of learning.</p>', '2026-03-23 10:41:49');

