INSERT INTO `testimonials` (`id`, `name`, `location_details`, `testimonial_details`, `created_at`) VALUES
(2, 'Dr. Shimu Saha', 'Sydney, Australia', '\"I cleared my first PTE exam through Ayanâ€™s Academy and achieved an incredible overall score of 81. This success would not have been possible without the personalized treatment. I received from every member of the Ayanâ€™s Academy faculty. \r\n\r\nThe institution provides elite exam preparation facilities and is managed by a Pearson-certified team who are genuinely friendly and eager to help you reach your goals. Overall, I had a fantastic experience collaborating with the entire Ayanâ€™s Academy teamâ€”their extensive focus and expert guidance were the keys to me hitting my target score.\"', '2026-03-23 10:39:25'),
(3, 'Charith Seneverathne', 'Srilanka', 'I had an excellent experience with Ayanâ€™s Academy for my PTE preparation. The guidance was clear, strategies were practical, and the mock tests truly reflected the real exam. Thanks to their support, I felt confident and achieved my target score. Highly recommended for anyone serious about PTE success!', '2026-04-11 11:21:41'),
(4, 'Faruk-ul-Alam', 'Dhaka, Bangladesh', 'Training at Ayanâ€™s Academy made a real difference in my PTE journey. The lessons were focused, the feedback was personalized, and the tips were incredibly effective. I improved quickly and felt fully prepared on test day. Definitely a great choice for PTE preparation!', '2026-04-11 11:24:28'),
